"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[86478],{40811:(e,n,t)=>{t.r(n),t.d(n,{data:()=>r});const r={key:"v-e65eb4c6",path:"/sqlserver/%E5%85%B6%E4%BB%96.html",title:"1. 基础操作",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"1.1. 连接",slug:"_1-1-连接",children:[{level:3,title:"1.1.1. 跨服务器连接",slug:"_1-1-1-跨服务器连接",children:[]}]},{level:2,title:"1.2. 结构",slug:"_1-2-结构",children:[{level:3,title:"1.2.1. SQL语句增加字段、修改字段、修改类型、修改默认值",slug:"_1-2-1-sql语句增加字段、修改字段、修改类型、修改默认值",children:[]}]},{level:2,title:"1.3. 导入导出",slug:"_1-3-导入导出",children:[{level:3,title:"1.3.1. 根据excel更新表数据（错误）",slug:"_1-3-1-根据excel更新表数据-错误",children:[]},{level:3,title:"1.3.2. excel操作（拷贝）",slug:"_1-3-2-excel操作-拷贝",children:[]}]},{level:2,title:"1.4. 系统",slug:"_1-4-系统",children:[{level:3,title:"1.4.1. 获取数据库表,列信息",slug:"_1-4-1-获取数据库表-列信息",children:[]},{level:3,title:"1.4.2. 获取表信息",slug:"_1-4-2-获取表信息",children:[]}]},{level:2,title:"2.1. 查询类库",slug:"_2-1-查询类库",children:[]},{level:2,title:"2.2. 事务操作",slug:"_2-2-事务操作",children:[]},{level:2,title:"2.3. 变量名必须唯一",slug:"_2-3-变量名必须唯一",children:[]},{level:2,title:"3.1. 查询指定ip地址的数据库",slug:"_3-1-查询指定ip地址的数据库",children:[]},{level:2,title:"3.2. 查询数据库中的表",slug:"_3-2-查询数据库中的表",children:[{level:3,title:"3.2.1. 多ip数据库操作",slug:"_3-2-1-多ip数据库操作",children:[]}]},{level:2,title:"",slug:"",children:[]},{level:2,title:"3.3. 根据属性值统计数量",slug:"_3-3-根据属性值统计数量",children:[]},{level:2,title:"3.4. 错误",slug:"_3-4-错误",children:[{level:3,title:"3.4.1. 因为文件组 'PRIMARY' 已满 的解决办法 有可能是磁盘剩余空间不足 导致的",slug:"_3-4-1-因为文件组-primary-已满-的解决办法-有可能是磁盘剩余空间不足-导致的",children:[]}]},{level:2,title:"3.5. 数据类型转换",slug:"_3-5-数据类型转换",children:[]},{level:2,title:"3.6. 生成序号的四种方式",slug:"_3-6-生成序号的四种方式",children:[]},{level:2,title:"3.7. SQL Server用游标循环遍历结果集",slug:"_3-7-sql-server用游标循环遍历结果集",children:[]}],git:{updatedTime:1653546536e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:2}]},filePathRelative:"sqlserver/其他.md"}},6221:(e,n,t)=>{t.r(n),t.d(n,{default:()=>P});var r=t(57293);const a=(0,r._)("h1",{id:"_1-基础操作",tabindex:"-1"},[(0,r._)("a",{class:"header-anchor",href:"#_1-基础操作","aria-hidden":"true"},"#"),(0,r.Uk)(" 1. "),(0,r._)("strong",null,"基础操作")],-1),s=(0,r._)("h2",{id:"_1-1-连接",tabindex:"-1"},[(0,r._)("a",{class:"header-anchor",href:"#_1-1-连接","aria-hidden":"true"},"#"),(0,r.Uk)(" 1.1. "),(0,r._)("strong",null,"连接")],-1),p=(0,r.Uk)("连接有两个注意事项：1、sql主服务保证开启 2、服务名写对了 如果你安装的时候没有改实例名 那么你的服务名就是localhost或"),i={href:"https://www.baidu.com/s?wd=127.0.0.1&tn=44039180_cpr&fenlei=mv6quAkxTZn0IZRqIHckPjm4nH00T1Y3rAcvmvPbmHTznHKhPHuh0ZwV5Hcvrjm3rH6sPfKWUMw85HfYnjn4nH6sgvPsT6KdThsqpZwYTjCEQLGCpyw9Uz4Bmy-bIi4WUvYETgN-TLwGUv3EP1RsrjRYnHbYrHDLnWn4nHcY",target:"_blank",rel:"noopener noreferrer"},l=(0,r.Uk)("127.0.0.1"),o=(0,r.Uk)("或计算机名或直接写个.(英文状态下) 都可以 如果改了实例名 那么就是 计算机名\\服务名"),d=(0,r.uE)('<h3 id="_1-1-1-跨服务器连接" tabindex="-1"><a class="header-anchor" href="#_1-1-1-跨服务器连接" aria-hidden="true">#</a> 1.1.1. <strong>跨服务器连接</strong></h3><p>1.执行存储过程 sp_addlinkedserver 以将服务器添加到 sys.servers。</p><p>--server124为远程服务器的别名</p><p>exec sp_addlinkedserver &#39;server124&#39;, &#39; &#39;, &#39;SQLOLEDB &#39;, &#39;远程服务器名或ip地址 &#39;</p><p>exec sp_addlinkedsrvlogin &#39;server124&#39;, &#39;false &#39;,null, &#39;用户名 &#39;, &#39;密码 &#39;</p><p>2.跨服务器查询时，需要按照下列格式指定查询表</p><p>添加的远程服务器别名</p><p>数据库名</p><p>数据库的schema，一般是dbo</p><p>表名称</p><p>查询示例</p><p>select * from server124.数据库名.dbo.表名</p><h2 id="_1-2-结构" tabindex="-1"><a class="header-anchor" href="#_1-2-结构" aria-hidden="true">#</a> 1.2. <strong>结构</strong></h2>',13),c={id:"_1-2-1-sql语句增加字段、修改字段、修改类型、修改默认值",tabindex:"-1"},u=(0,r._)("a",{class:"header-anchor",href:"#_1-2-1-sql语句增加字段、修改字段、修改类型、修改默认值","aria-hidden":"true"},"#",-1),m=(0,r.Uk)(" 1.2.1. "),g={href:"http://www.cnblogs.com/songjiali/p/4223332.html",target:"_blank",rel:"noopener noreferrer"},v=(0,r._)("strong",null,"SQL语句增加字段、修改字段、修改类型、修改默认值",-1),b=(0,r.uE)('<p>一、修改字段默认值</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>alter table 表名 drop constraint 约束名字  ------说明：删除表的字段的原有约束\n\nalter table 表名 add constraint 约束名字 DEFAULT 默认值 for 字段名称 -------说明：添加一个表的字段的约束并指定默认值\n\n二、修改字段名：\n\nalter table 表名 rename column A to B\n\n三、修改字段类型：\n\nalter table 表名 alter column UnitPrice decimal(18, 4) not null \n\n三、修改增加字段：\n\nalter table 表名 ADD 字段 类型 NOT NULL Default 0\n\n \n\nupdate dbo.Resources_XiaoBan set Xiaobanid=\n\n(\n\n \n\n select top 1 b.Number from [ZJ_SLZY].[dbo].[XIAOBAN_PY$] b where Resources_XiaoBan.JOINID=b.JOINID AND Resources_XiaoBan.MIAN_JI=b.MIAN_JI \n\n) WHERE XIAN=&#39;330824&#39;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_1-3-导入导出" tabindex="-1"><a class="header-anchor" href="#_1-3-导入导出" aria-hidden="true">#</a> 1.3. <strong>导入导出</strong></h2><h3 id="_1-3-1-根据excel更新表数据-错误" tabindex="-1"><a class="header-anchor" href="#_1-3-1-根据excel更新表数据-错误" aria-hidden="true">#</a> 1.3.1. <strong>根据excel更新表数据（错误）</strong></h3><p>（一）右键数据库-任务-导入数据</p><p>（二）选择数据源-excel</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201231624192.jpg" alt="img"></p><p>（3）选择目标</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201231624193.jpg" alt="img"></p><p>（4）编写查询以指定要传输的数据</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201231624194.jpg" alt="img"></p><p>64729</p><p>64730</p><p>60058</p><p>4645</p><h3 id="_1-3-2-excel操作-拷贝" tabindex="-1"><a class="header-anchor" href="#_1-3-2-excel操作-拷贝" aria-hidden="true">#</a> 1.3.2. <strong>excel操作（拷贝）</strong></h3><p>SQL SERVER 和EXCEL的数据导入导出</p><p>1、在SQL SERVER里查询Excel数据:</p><p>-- ======================================================</p><p><strong>SELECT</strong> *</p><p><strong>FROM</strong> OpenDataSource( &#39;Microsoft.Jet.OLEDB.4.0&#39;,</p><p>&#39;Data Source=&quot;c:\\book1.xls&quot;;User ID=Admin;Password=;Extended properties=Excel 5.0&#39;)...[Sheet1$]</p><p>下面是个查询的示例，它通过用于 Jet 的 OLE DB 提供程序查询 Excel 电子表格。</p><p><strong>SELECT</strong> *</p><p><strong>FROM</strong> OpenDataSource ( &#39;Microsoft.Jet.OLEDB.4.0&#39;,</p><p>&#39;Data Source=&quot;c:\\Finance\\account.xls&quot;;User ID=Admin;Password=;Extended properties=Excel 5.0&#39;)...xactions</p><p>-------------------------------------------------------------------------------------------------</p><p>2、将Excel的数据导入SQL server :</p><p>-- ======================================================</p><p><strong>SELECT</strong> * <strong>into</strong> newtable</p><p><strong>FROM</strong> OpenDataSource( &#39;Microsoft.Jet.OLEDB.4.0&#39;,</p><p>&#39;Data Source=&quot;c:\\book1.xls&quot;;User ID=Admin;Password=;Extended properties=Excel 5.0&#39;)...[Sheet1$]</p><p>实例:</p><p><strong>SELECT</strong> * <strong>into</strong> newtable</p><p><strong>FROM</strong> OpenDataSource( &#39;Microsoft.Jet.OLEDB.4.0&#39;,</p><p>&#39;Data Source=&quot;c:\\Finance\\account.xls&quot;;User ID=Admin;Password=;Extended properties=Excel 5.0&#39;)...xactions</p><p>-------------------------------------------------------------------------------------------------</p><p>3、将SQL SERVER中查询到的数据导成一个Excel文件</p><p>-- ======================================================</p><p>T-SQL代码：</p><p><strong>EXEC</strong> master..xp_cmdshell &#39;bcp 库名.dbo.表名out c:\\Temp.xls -c -q -S&quot;servername&quot; -U&quot;sa&quot; -P&quot;&quot;&#39;</p><p>参数：S 是SQL服务器名；U是用户；P是密码</p><p>说明：还可以导出文本文件等多种格式</p><p>实例:<strong>EXEC</strong> master..xp_cmdshell &#39;bcp saletesttmp.dbo.CusAccount out c:\\temp1.xls -c -q -S&quot;pmserver&quot; -U&quot;sa&quot; -P&quot;sa&quot;&#39;</p><p><strong>EXEC</strong> master..xp_cmdshell &#39;bcp &quot;SELECT au_fname, au_lname FROM pubs..authors ORDER BY au_lname&quot; queryout C:\\ authors.xls -c -Sservername -Usa -Ppassword&#39;</p><p>在VB6中应用ADO导出EXCEL文件代码：</p><p>Dim cn <strong>As</strong> New ADODB.<strong>Connection</strong></p><p>cn.<strong>open</strong> &quot;Driver={SQL Server};Server=WEBSVR;DataBase=WebMis;UID=sa;WD=123;&quot;</p><p>cn.<strong>execute</strong> &quot;master..xp_cmdshell &#39;bcp &quot;<strong>SELECT</strong> col1, col2 <strong>FROM</strong> 库名.dbo.表名&quot; queryout E:\\DT.xls -c -Sservername -Usa -Ppassword&#39;&quot;</p><p>------------------------------------------------------------------------------------------------</p><p>4、在SQL SERVER里往Excel插入数据:</p><p>-- ======================================================</p><p><strong>insert</strong> <strong>into</strong> OpenDataSource( &#39;Microsoft.Jet.OLEDB.4.0&#39;,</p><p>&#39;Data Source=&quot;c:\\Temp.xls&quot;;User ID=Admin;Password=;Extended properties=Excel 5.0&#39;)...table1 (A1,A2,A3) <strong>values</strong> (1,2,3)</p><p>T-SQL代码：</p><p><strong>INSERT</strong> <strong>INTO</strong></p><p>OPENDATASOURCE(&#39;Microsoft.JET.OLEDB.4.0&#39;,</p><p>&#39;Extended Properties=Excel 8.0;Data source=C:\\training\\inventur.xls&#39;)...[Filiale1$]</p><p>(bestand, produkt) <strong>VALUES</strong> (20, &#39;Test&#39;)</p><h2 id="_1-4-系统" tabindex="-1"><a class="header-anchor" href="#_1-4-系统" aria-hidden="true">#</a> 1.4. <strong>系统</strong></h2><h3 id="_1-4-1-获取数据库表-列信息" tabindex="-1"><a class="header-anchor" href="#_1-4-1-获取数据库表-列信息" aria-hidden="true">#</a> 1.4.1. <strong>获取数据库表,列信息</strong></h3><p>SELECT 表名 =</p><p>​ CASE WHEN a.colorder=1 THEN d.name</p><p>​ ELSE &#39;&#39;</p><p>​ END,</p><p>​ 表说明 =</p><p>​ CASE WHEN a.colorder=1 THEN ISNULL(f.value,&#39;&#39;)</p><p>​ ELSE &#39;&#39;</p><p>​ END,</p><p>​ 字段序号 = a.colorder,字段名 = a.name,</p><p>​ 标识 =</p><p>​ CASE WHEN COLUMNPROPERTY(a.id,a.name,&#39;IsIdentity&#39;)=1 THEN &#39;√&#39;</p><p>​ ELSE &#39;×&#39;</p><p>​ END,</p><p>​ 主键 =</p><p>​ CASE WHEN EXISTS ( SELECT 1</p><p>​ FROM sysobjects</p><p>​ WHERE xtype=&#39;PK&#39;</p><p>​ AND name IN (</p><p>​ SELECT name</p><p>​ FROM sysindexes</p><p>​ WHERE indid IN (</p><p>​ SELECT indid</p><p>​ FROM sysindexkeys</p><p>​ WHERE id=a.id</p><p>​ AND colid=a.colid)) )</p><p>​ THEN &#39;√&#39;</p><p>​ ELSE &#39;×&#39;</p><p>​ END,</p><p>​ 类型 = b.name,</p><p>​ 占用字节数 = a.length,</p><p>​ 长度 = COLUMNPROPERTY(a.id,a.name,&#39;PRECISION&#39;),</p><p>​ 小数位数 = ISNULL(COLUMNPROPERTY(a.id,a.name,&#39;Scale&#39;),0),</p><p>​ 允许空 =</p><p>​ CASE WHEN a.isnullable=1 THEN &#39;√&#39;</p><p>​ ELSE &#39;×&#39;</p><p>​ END,</p><p>​ 默认值 = ISNULL(e.text,&#39;&#39;),</p><p>​ 字段说明 = ISNULL(g.[value],&#39;&#39;)</p><p>FROM syscolumns a</p><p>LEFT JOIN systypes b</p><p>​ ON a.xusertype=b.xusertype</p><p>INNER JOIN sysobjects d</p><p>​ ON a.id=d.id AND d.xtype=&#39;U&#39; AND d.name&lt;&gt;&#39;dtproperties&#39;</p><p>LEFT JOIN syscomments e</p><p>​ ON a.cdefault=e.id</p><p>LEFT JOIN sys.extended_properties g</p><p>​ ON a.id=g.major_id AND a.colid=g.minor_id</p><p>LEFT JOIN sys.extended_properties f</p><p>​ ON d.id=f.major_id AND f.minor_id=0 --where d.name=&#39;Map_Layers&#39; --如果只查询指定表,加上此条件</p><p>ORDER BY a.id,a.colorder;</p><h3 id="_1-4-2-获取表信息" tabindex="-1"><a class="header-anchor" href="#_1-4-2-获取表信息" aria-hidden="true">#</a> 1.4.2. <strong>获取表信息</strong></h3><p>select a.name ,ISNULL(b.value,&#39;&#39;) as remark from sysobjects a left join sys.extended_properties b on a.id=b.major_id AND b.minor_id=0 where a.xtype=&#39;U&#39;</p><h1 id="_2-c" tabindex="-1"><a class="header-anchor" href="#_2-c" aria-hidden="true">#</a> 2. <strong>c#</strong></h1><h2 id="_2-1-查询类库" tabindex="-1"><a class="header-anchor" href="#_2-1-查询类库" aria-hidden="true">#</a> 2.1. <strong>查询类库</strong></h2><p>public static DataSet ExecuteDataSetBySql(string strSql)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlDataAdapter da = new SqlDataAdapter(strSql, conn);</p><p>​ DataSet ds = new DataSet();</p><p>​ da.Fill(ds);</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return ds;</p><p>​ }</p><p>​ public static DataSet ExecuteDataSetBySql(string strSql, SqlParameter[] parameters)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlCommand cmd = new SqlCommand(strSql, conn);</p><p>​ if (parameters != null)</p><p>​ {</p><p>​ //SqlParameterCollection 只接受非空的 SqlParameter 类型对象，不接受 SqlParameter[] 对象。</p><p>​ foreach (SqlParameter sqlParameter in parameters)</p><p>​ {</p><p>​ cmd.Parameters.Add(sqlParameter);</p><p>​ }</p><p>​ }</p><p>​ SqlDataAdapter da = new SqlDataAdapter(cmd);</p><p>​ DataSet ds = new DataSet();</p><p>​ da.Fill(ds);</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return ds;</p><p>​ }</p><p>​ public static DataTable ExecuteDataTableBySql(string strSql)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlDataAdapter da = new SqlDataAdapter(strSql, conn);</p><p>​ DataTable dt = new DataTable();</p><p>​ da.Fill(dt);</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return dt;</p><p>​ }</p><p>​ public static DataTable ExecuteDataTableBySql(string strSql, SqlParameter[] parameters)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlCommand cmd = new SqlCommand(strSql, conn);</p><p>​ if (parameters != null)</p><p>​ {</p><p>​ //SqlParameterCollection 只接受非空的 SqlParameter 类型对象，不接受 SqlParameter[] 对象。</p><p>​ foreach (SqlParameter sqlParameter in parameters)</p><p>​ {</p><p>​ cmd.Parameters.Add(sqlParameter);</p><p>​ }</p><p>​ }</p><p>​ SqlDataAdapter da = new SqlDataAdapter(cmd);</p><p>​ DataTable dt = new DataTable();</p><p>​ da.Fill(dt);</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return dt;</p><p>​ }</p><p>​ public static DataTable ExecuteDataTableBySql(string strSql, SqlParameter[] parameters, string connString)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(connString);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlCommand cmd = new SqlCommand(strSql, conn);</p><p>​ if (parameters != null)</p><p>​ {</p><p>​ //SqlParameterCollection 只接受非空的 SqlParameter 类型对象，不接受 SqlParameter[] 对象。</p><p>​ foreach (SqlParameter sqlParameter in parameters)</p><p>​ {</p><p>​ cmd.Parameters.Add(sqlParameter);</p><p>​ }</p><p>​ }</p><p>​ SqlDataAdapter da = new SqlDataAdapter(cmd);</p><p>​ DataTable dt = new DataTable();</p><p>​ da.Fill(dt);</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return dt;</p><p>​ }</p><p>​ public static int ExecuteNonQueryBySql(string strSql)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlCommand cmd = new SqlCommand(strSql, conn);</p><p>​ conn.Open();</p><p>​ int rows = cmd.ExecuteNonQuery();</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return rows;</p><p>​ }</p><p>​ public static int ExecuteNonQueryBySql(string strSql, SqlParameter[] parameters)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlCommand cmd = new SqlCommand(strSql, conn);</p><p>​ foreach (SqlParameter sqlParameter in parameters)</p><p>​ {</p><p>​ cmd.Parameters.Add(sqlParameter);</p><p>​ }</p><p>​ conn.Open();</p><p>​ int rows = cmd.ExecuteNonQuery();</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return rows;</p><p>​ }</p><p>​ public static object ExecuteScalarBySql(string strSql)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlCommand cmd = new SqlCommand(strSql, conn);</p><p>​ conn.Open();</p><p>​ object obj = cmd.ExecuteScalar();</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return obj;</p><p>​ }</p><p>​ public static object ExecuteScalarBySql(string strSql, SqlParameter[] parameters)</p><p>​ {</p><p>​ string dbstr = Utility.ConfigHelper.GetConnectionStringsConfig(&quot;Conn&quot;);</p><p>​ SqlConnection conn = new SqlConnection(dbstr);</p><p>​ SqlCommand cmd = new SqlCommand(strSql, conn);</p><p>​ foreach (SqlParameter sqlParameter in parameters)</p><p>​ {</p><p>​ cmd.Parameters.Add(sqlParameter);</p><p>​ }</p><p>​ conn.Open();</p><p>​ object obj = cmd.ExecuteScalar();</p><p>​ conn.Close();</p><p>​ conn.Dispose();</p><p>​ return obj;</p><p>​ }</p><h2 id="_2-2-事务操作" tabindex="-1"><a class="header-anchor" href="#_2-2-事务操作" aria-hidden="true">#</a> 2.2. <strong>事务操作</strong></h2><p>事务是指用户定义的一个数据库操作序列，这些操作要么全做要么全不做，它是一个不可分割的工作单位。一个事务可以是一条SQL语句，一组SQL语句，或整个程序。</p><p>\\1. <strong>public</strong> <strong>bool</strong> transactionOp()</p><p>\\2. {</p><p>\\3. // 事务成功返回true，事务失败返回false</p><p>\\4. <strong>bool</strong> result = <strong>false</strong>;</p><p>\\5. <strong>string</strong> SqlConnectionString = &quot;Data Source=.;Initial Catalog=DataBaseName;User ID=sa;pwd=123456;Connection Lifetime=0;max pool size=200&quot;;</p><p>\\6. SqlConnection cn = <strong>new</strong> SqlConnection(SqlConnectionString);</p><p>\\7. SqlCommand cmd = <strong>new</strong> SqlCommand();</p><p>\\8. SqlTransaction transaction = <strong>null</strong>;</p><p>\\9.</p><p>\\10. <strong>try</strong></p><p>\\11. {</p><p>\\12. // 打开数据库</p><p>\\13. <strong>if</strong> (cn.State == ConnectionState.Closed)</p><p>\\14. {</p><p>\\15. cn.Open();</p><p>\\16. }</p><p>\\17.</p><p>\\18. // 开始事务</p><p>\\19. transaction = cn.BeginTransaction();</p><p>\\20. cmd.Transaction = transaction;</p><p>\\21. cmd.Connection = cn;</p><p>\\22.</p><p>\\23. // 执行第一条SQL语句</p><p>\\24. cmd.CommandType = CommandType.Text;</p><p>\\25. cmd.CommandText = &quot;insert into Users values(&#39;admin&#39;, &#39;admin&#39;)&quot;;</p><p>\\26. <strong>if</strong> (cmd.ExecuteNonQuery() &lt; 0)</p><p>\\27. <strong>throw</strong> <strong>new</strong> Exception();</p><p>\\28.</p><p>\\29. // 执行第二条SQL语句</p><p>\\30. cmd.CommandType = CommandType.Text;</p><p>\\31. cmd.CommandText = &quot;update Users set pwd = &#39;123456&#39; where name = &#39;小明&#39;&quot;;</p><p>\\32. <strong>if</strong> (cmd.ExecuteNonQuery() &lt; 0)</p><p>\\33. <strong>throw</strong> <strong>new</strong> Exception();</p><p>\\34.</p><p>\\35. // 提交事务</p><p>\\36. transaction.Commit();</p><p>\\37. result = <strong>true</strong>;</p><p>\\38. }</p><p>\\39. <strong>catch</strong></p><p>\\40. {</p><p>\\41. result = <strong>false</strong>;</p><p>\\42. // 回滚事务</p><p>\\43. transaction.Rollback();</p><p>\\44. }</p><p>\\45. <strong>finally</strong></p><p>\\46. {</p><p>\\47. // 关闭数据库</p><p>\\48. <strong>if</strong> (cn.State == ConnectionState.Open)</p><p>\\49. {</p><p>\\50. cn.Close();</p><p>\\51. }</p><p>\\52. cn.Dispose();</p><p>\\53. cmd.Dispose();</p><p>\\54. transaction.Dispose();</p><p>\\55. }</p><p>\\56. <strong>return</strong> result;</p><p>\\57. }</p><h2 id="_2-3-变量名必须唯一" tabindex="-1"><a class="header-anchor" href="#_2-3-变量名必须唯一" aria-hidden="true">#</a> 2.3. <strong>变量名必须唯一</strong></h2><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201231624195.jpg" alt="img"></p><p>http://blog.csdn.net/tr1912/article/details/50605579?utm_source=itdadao&amp;utm_medium=referral</p><h1 id="_3-实用项" tabindex="-1"><a class="header-anchor" href="#_3-实用项" aria-hidden="true">#</a> 3. <strong>实用项</strong></h1><h2 id="_3-1-查询指定ip地址的数据库" tabindex="-1"><a class="header-anchor" href="#_3-1-查询指定ip地址的数据库" aria-hidden="true">#</a> 3.1. <strong>查询指定ip地址的数据库</strong></h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>/// &lt;summary&gt;\n\n  /// 获取指定IP地址的数据库所有数据库实例名。\n\n  /// &lt;/summary&gt;\n\n/// &lt;param name=&quot;i&quot;&gt;指定的 IP 地址。&lt;/param&gt;\n\n  /// &lt;param name=&quot;username&quot;&gt;登录数据库的用户名。&lt;/param&gt;\n\n  /// &lt;param name=&quot;password&quot;&gt;登陆数据库的密码。&lt;/param&gt;\n\n  /// &lt;returns&gt;返回包含数据实例名的列表。&lt;/returns&gt;\n\n  private ArrayList GetAllDataBase(string ip, string username, string password)\n\n  {\n\n​    ArrayList DBNameList = new ArrayList();\n\n​    SqlConnection Connection = new SqlConnection(\n\n​      String.Format(&quot;Data Source={0};Initial Catalog = master;User ID = {1};PWD = {2}&quot;, ip, username, password));\n\n​    DataTable DBNameTable = new DataTable();\n\n​    SqlDataAdapter Adapter = new SqlDataAdapter(&quot;select name from master..sysdatabases&quot;, Connection);\n\n \n\n​    lock (Adapter)\n\n​    {\n\n​      Adapter.Fill(DBNameTable);\n\n​    }\n\n \n\n​    foreach (DataRow row in DBNameTable.Rows)\n\n    {\n\n      DBNameList.Add(row[&quot;name&quot;]);\n\n    }\n\n \n\n    return DBNameList;\n\n  }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-2-查询数据库中的表" tabindex="-1"><a class="header-anchor" href="#_3-2-查询数据库中的表" aria-hidden="true">#</a> 3.2. <strong>查询数据库中的表</strong></h2><p>如何获得数据库里所有表的名字</p><p>平时我们操作比较多的都是表里的数据，也许突然有一天会需要把所有表的名字都列出来看一看——比如，你的论坛是按每个版块一个表来管理的，这时候你要在首页列出各版块的名字。应该怎么办呢？</p><p>肯定得用SELECT吧……但我们平时使用SELECT操作的数据都是表里的数据，表的名字并不是表的数据，这可怎么办呢？</p><p>你可能会想：“功能强大的SQL Server不会连这么简单的功能都实现不了吧？一定会把所有表的名字存储在某个表里……”注意啦！在这儿我要</p><p>小小地偷换一下概念了——视图（View）也算是一种“表”，只不过它是由固定查询形成的一种“虚拟表”。</p><p>OK，你猜对啦！由SQL Server管理的每个数据库里都有一个名为sysobjects的视图，它是system级别的，所以它的全限定名是——sys.sysobjects</p><p>你可能又会问：“为什么不是sys.tables而是sys.objects呢？”问的好！因为这张表里存储的可不光是数据库里的表，它存储的是一个数据库中</p><p>所有的“对象”——杂七杂八包括了表的主键、存储过程、触发器等等，一共是24种——表（Table，确切地说是“用户自定义表”）只是这24种对象中的一种。</p><p>剩下的事情……吼吼……</p><p>执行下面的查询语句，可以得到所有包含在sys.sysobjects视图里的数据</p><p>USE AdventureWorks</p><p>SELECT *</p><p>FROM sys.sysobjects</p><p>GO</p><p>得出数据后，请注意名为type的列——这一列标明了对象的类型，也就是前面提到的24种。在这里，我用一个表格把它们列出来：</p><p>AF = Aggregate function (CLR)</p><p>C = CHECK constraint</p><p>D = DEFAULT (constraint or stand-alone)</p><p>F = FOREIGN KEY constraint</p><p>FN = SQL scalar function</p><p>FS = Assembly (CLR) scalar function</p><p>FT = Assembly (CLR) table-valued function</p><p>IF = SQL inline table-valued function</p><p>IT = Internal table</p><p>P = SQL stored procedure</p><p>PC = Assembly (CLR) stored procedure</p><p>PK = PRIMARY KEY constraint</p><p>R = Rule (old-style, stand-alone)</p><p>RF = Replication-filter-procedure</p><p>S = System base table</p><p>SN = Synonym</p><p>SQ = Service queue</p><p>TA = Assembly (CLR) DML trigger</p><p>TF = SQL table-valued-function</p><p>TR = SQL DML trigger</p><p>U = Table (user-defined)</p><p>UQ = UNIQUE constraint</p><p>V = View</p><p>X = Extended stored procedure</p><p>OK，我们要得到名称的表（用户自定义表）就是类型为“U”的对象；而sys.objects的类型为“S”。所以，为了达到我们的最终目的，SQL语句应</p><p>该是——</p><p>USE AdventureWorks SELECT name FROM sys.sysobjects WHERE type=&#39;U&#39;</p><p>GO</p><h3 id="_3-2-1-多ip数据库操作" tabindex="-1"><a class="header-anchor" href="#_3-2-1-多ip数据库操作" aria-hidden="true">#</a> 3.2.1. <strong>多ip数据库操作</strong></h3><p>//创建链接服务器【在本地服务器创建】</p><p>exec sp_addlinkedserver &#39;linkserver&#39;,&#39;&#39;,&#39;SQLOLEDB&#39;,&#39;192.168.0.4&#39;</p><p>//登录链接服务器</p><p>-- exec sp_addlinkedserver &#39;链接服务器名称&#39;,&#39;&#39;,&#39;SQLOLEDB&#39;,&#39;远程地址&#39;</p><p>exec sp_addlinkedsrvlogin &#39;linkserver&#39;,&#39;false&#39;,null,&#39;sa&#39;,&#39;hzgzsoft63967273&#39;</p><p>select * from linkserver.HZGZSoftBasic.dbo.DM_SHU_ZHONG</p><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h2><h2 id="_3-3-根据属性值统计数量" tabindex="-1"><a class="header-anchor" href="#_3-3-根据属性值统计数量" aria-hidden="true">#</a> 3.3. <strong>根据属性值统计数量</strong></h2><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>select sum(dd.c1) as &#39;331181&#39;,sum(dd.c2) as &#39;330881&#39; from (\n\nselect case when CodeId=&#39;331181&#39; then c end as c1,case when CodeId=&#39;330881&#39; then c end as c2\n\n from ( \n\n select CodeId ,COUNT(*) as c from dbo.Map_FeatureJWD GROUP BY CodeId \n\n ) as a) as dd\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202201231624196.jpg" alt="img"></p><h2 id="_3-4-错误" tabindex="-1"><a class="header-anchor" href="#_3-4-错误" aria-hidden="true">#</a> 3.4. <strong>错误</strong></h2>',370),h={id:"_3-4-1-因为文件组-primary-已满-的解决办法-有可能是磁盘剩余空间不足-导致的",tabindex:"-1"},S=(0,r._)("a",{class:"header-anchor",href:"#_3-4-1-因为文件组-primary-已满-的解决办法-有可能是磁盘剩余空间不足-导致的","aria-hidden":"true"},"#",-1),q=(0,r.Uk)(" 3.4.1. "),E={href:"http://www.cnblogs.com/haoliansheng/p/4278992.html",target:"_blank",rel:"noopener noreferrer"},C=(0,r._)("strong",null,"因为文件组 'PRIMARY' 已满 的解决办法 有可能是磁盘剩余空间不足 导致的",-1),_=(0,r._)("p",null,"一般虚拟主机提供商是通过限制数据库文件的大小来实现提供定制的数据库空间的。当你把从虚拟数据库空间备份下来的文件恢复到自己的服务器上时，这个限制还是存在的。 找到数据库文件",-1),x=(0,r._)("p",null,"给增加个数据文件就好了",-1),D=(0,r._)("p",null,"解决办法： 1.检查你的磁盘剩余空间是否足够,如果没有磁盘剩余空间,则清理磁盘,腾出空间。 2.检查你的磁盘分区格式：如果是FAT16,则数据文件最大只能是2G，如果是FAT32,则数据文件最大只能是4G，改为NTFS分区则没有这种限制。 3.检查一下你有没有限制数据库文件的大小： 企业管理器--右键你的数据库--属性--文件增长限制--如果有限制大小,取消限制。 4.检查你的SQL版本,如果你用MSDE,则限制了数据文件最大是2G。 5.你也可以为 primary 组添加新的数据文件来解决这个问题 alter database 库名 add file(NAME = 逻辑文件名,FILENAME = 'c:实际文件名.ndf'。（其实通过企业管理器选择数据库\"属性\"》数据库文件更方便。",-1),f=(0,r._)("p",null,"通过新增一个NDF，问题得到解决！",-1),L={id:"_3-5-数据类型转换",tabindex:"-1"},y=(0,r._)("a",{class:"header-anchor",href:"#_3-5-数据类型转换","aria-hidden":"true"},"#",-1),T=(0,r.Uk)(" 3.5. "),w={href:"https://www.cnblogs.com/wangzhaofang/p/8297944.html",target:"_blank",rel:"noopener noreferrer"},N=(0,r._)("strong",null,"数据类型转换",-1),A=(0,r.uE)('<div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>//CAST(表达式 AS 数据类型) \n源代码：\nSELECT StudentName + &#39;的出生日期是&#39; +CAST(BornDate as varchar(50)) AS &#39;学生信息&#39; FROM Student\n\n//CONVERT(数据类型，表达式，样式 ) \nSELECT StudentName,CONVERT(varchar(50),BornDate,102) AS 出生日期 FROM Student\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-6-生成序号的四种方式" tabindex="-1"><a class="header-anchor" href="#_3-6-生成序号的四种方式" aria-hidden="true">#</a> 3.6. <strong>生成序号的四种方式</strong></h2><p>https://blog.csdn.net/qq_30725967/article/details/88572541</p><h2 id="_3-7-sql-server用游标循环遍历结果集" tabindex="-1"><a class="header-anchor" href="#_3-7-sql-server用游标循环遍历结果集" aria-hidden="true">#</a> 3.7. <strong>SQL Server用游标循环遍历结果集</strong></h2><p>https://blog.csdn.net/ClearLoveQ/article/details/83579287</p>',5),O={},P=(0,t(63243).Z)(O,[["render",function(e,n){const t=(0,r.up)("ExternalLinkIcon");return(0,r.wg)(),(0,r.iD)(r.HY,null,[a,s,(0,r._)("p",null,[p,(0,r._)("a",i,[l,(0,r.Wm)(t)]),o]),d,(0,r._)("h3",c,[u,m,(0,r._)("a",g,[v,(0,r.Wm)(t)])]),b,(0,r._)("h3",h,[S,q,(0,r._)("a",E,[C,(0,r.Wm)(t)])]),_,x,D,f,(0,r._)("h2",L,[y,T,(0,r._)("a",w,[N,(0,r.Wm)(t)])]),A],64)}]])},63243:(e,n)=>{n.Z=(e,n)=>{const t=e.__vccOpts||e;for(const[e,r]of n)t[e]=r;return t}}}]);